#include <SPI.h>
extern int pid_heater_control(float,float,float,float,float,float,float*,float*);
extern uint8_t zone_arbitrate(float*,uint8_t,uint8_t);
#define ZONES 4
const int cs[]={6,7,8,9},ssr[]={2,3,4,5};
float sp[ZONES]={60,65,70,75},pv[ZONES];
float ig[ZONES]={0,0,0,0},le[ZONES]={0,0,0,0};
uint8_t act=0;
void rtd_setup(){
  SPI.begin();
  for(int i=0;i<ZONES;i++){pinMode(cs[i],OUTPUT);digitalWrite(cs[i],HIGH);}}
float rtd_read(uint8_t z){
  SPI.beginTransaction(SPISettings(1000000,MSBFIRST,SPI_MODE1));
  digitalWrite(cs[z],LOW);
  uint16_t v=((uint16_t)SPI.transfer(0)<<8)|SPI.transfer(0);
  digitalWrite(cs[z],HIGH);
  SPI.endTransaction();
  if(v&0x01)return -999.0f;
  return(v>>1)*0.03125f-256.0f;}
void ssr_setup(){for(int i=0;i<ZONES;i++){pinMode(ssr[i],OUTPUT);digitalWrite(ssr[i],LOW);}}
void ssr_set(uint8_t z,bool on){for(int i=0;i<ZONES;i++)digitalWrite(ssr[i],(i==z&&on)?HIGH:LOW);}
void fault_check(){
  for(int i=0;i<ZONES;i++)if(pv[i]<-100){ssr_set(0,false);
    Serial.print("FAULT:RTD");Serial.println(i);}}
void modbus_tick(){}
unsigned long pt=0;
void setup(){Serial.begin(115200);rtd_setup();ssr_setup();}
void loop(){
  unsigned long n=millis();
  float dt=(n-pt)/1000.0f;
  if(dt<0.1f)return;pt=n;
  for(int i=0;i<ZONES;i++)pv[i]=rtd_read(i);
  fault_check();
  float errs[ZONES];
  for(int i=0;i<ZONES;i++){
    float dec=0;
    for(int j=0;j<ZONES;j++)if(j!=i)dec+=0.05f*(pv[j]-sp[j]);
    errs[i]=(sp[i]-dec)-pv[i];}
  act=zone_arbitrate(errs,ZONES,act);
  int pw=pid_heater_control(sp[act]+errs[act]-(sp[act]-pv[act]),pv[act],dt,2.0f,0.1f,0.05f,&ig[act],&le[act]);
  ssr_set(act,pw>128);
  modbus_tick();
  for(int i=0;i<ZONES;i++){Serial.print(pv[i],1);Serial.print(',');}Serial.println();}
